import React from 'react';
import { auth } from "@/auth";
import { db } from "@/db/drizzle";
import { resumeHistory } from "@/db/schema";
import { desc } from "drizzle-orm";
import { redirect } from "next/navigation";
import HistoryTable from "@/components/HistoryTable";

// Hardcoded Admin List
const ADMIN_EMAILS = ["thotajonathan.249@gmail.com"];

export default async function AdminPage() {
    const session = await auth();

    // 1. Security Check
    if (!session?.user?.email || !ADMIN_EMAILS.includes(session.user.email)) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 text-center p-4">
                <h1 className="text-4xl font-bold text-red-600 mb-4">Access Denied</h1>
                <p className="text-gray-600 max-w-md">
                    This area is restricted to administrators only.
                    If you believe this is a mistake, please contact support.
                </p>
            </div>
        );
    }

    // 2. Fetch ALL history (No user filter)
    const history = await db
        .select()
        .from(resumeHistory)
        .orderBy(desc(resumeHistory.createdAt));

    return (
        <div className="min-h-screen bg-gray-50 p-6 md:p-12 font-sans text-gray-900">
            <div className="max-w-7xl mx-auto space-y-8">

                {/* Header */}
                <div className="flex items-center justify-between animate-fade-in-up">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight text-indigo-900">Admin Dashboard</h1>
                        <p className="text-gray-500">Global View: All Employee Logins & History</p>
                    </div>
                    <div className="bg-indigo-100 text-indigo-700 px-4 py-2 rounded-lg font-medium">
                        Admin Mode: Active
                    </div>
                </div>

                {/* Reusing the reliable HistoryTable component */}
                {/* We pass "Admin View" as the username to indicate this isn't a single user's profile */}
                <HistoryTable
                    history={history}
                    userName="Global Admin View"
                    showUserColumn={true}
                />
            </div>
        </div>
    );
}

import { auth } from "@/auth";
