import { NextResponse } from 'next/server';
import { getDeepSeekClient } from '@/utils/ai-client';
import { getExtractJDPrompt, getContactInfoPrompt } from '@/lib/prompts/extract-jd-prompt';
import { auth } from '@/auth';

export const dynamic = 'force-dynamic';

export async function POST(req: Request) {
    try {
        const { text, mode, source, link, candidateName } = await req.json();

        if (!text) {
            return NextResponse.json({ error: "No text provided" }, { status: 400 });
        }

        const deepseek = getDeepSeekClient();
        const isContactOnly = mode === 'contact_only';
        const systemPrompt = isContactOnly ? getContactInfoPrompt(text) : getExtractJDPrompt(text);

        const completion = await deepseek.chat.completions.create({
            messages: [{ role: "user", content: systemPrompt }],
            model: "deepseek-chat",
            temperature: 0.1,
        });

        const rawContent = completion.choices[0]?.message?.content || "{}";
        console.log(`DeepSeek Raw Content (Mode: ${mode || 'full'}):`, rawContent);
        let parsedData;

        try {
            // Robust JSON extraction: Find first { and last }
            const jsonStart = rawContent.indexOf('{');
            const jsonEnd = rawContent.lastIndexOf('}');

            if (jsonStart !== -1 && jsonEnd !== -1) {
                const jsonStr = rawContent.substring(jsonStart, jsonEnd + 1);
                parsedData = JSON.parse(jsonStr);
            } else {
                if (isContactOnly) throw new Error("No JSON in contact extraction");
                throw new Error("No JSON object found in response");
            }
        } catch (e) {
            console.error("Failed to parse JD JSON:", e);
            // Fallback: If JSON fails, treat the whole content as the cleaned JD
            parsedData = {
                cleaned_jd: rawContent.replace(/```json/g, '').replace(/```/g, ''),
                recruiter_name: null,
                recruiter_email: null
            };
        }

        // Sheet logging side-effect removed for local/stable mode

        return NextResponse.json({
            // If contact only, do NOT return cleaned_jd (keep original on client)
            cleaned_jd: isContactOnly ? undefined : (parsedData.cleaned_jd || ""),
            job_role: parsedData.job_role || null,
            location: parsedData.location || null,
            rate: parsedData.rate || null,
            job_type: parsedData.job_type || null,
            work_style: parsedData.work_style || null,
            recruiter_name: parsedData.recruiter_name || null,
            recruiter_email: parsedData.recruiter_email || null,
            recruiter_phone: parsedData.recruiter_phone || null,
            sheet_id: null // Explicitly null as sheets integration is decommissioned
        });

    } catch (error: unknown) {
        console.error("Extraction Error:", error);
        const errorMessage = error instanceof Error ? error.message : "Internal Server Error";
        return NextResponse.json({ error: errorMessage }, { status: 500 });
    }
}

import NextAuth from "next-auth"
import Google from "next-auth/providers/google"

interface ExtendedToken {
    accessToken?: string;
    expiresAt?: number;
    refreshToken?: string;
    user?: {
        name?: string | null;
        email?: string | null;
        image?: string | null;
    };
    error?: string;
}

// Helper to refresh the token
async function refreshAccessToken(token: ExtendedToken): Promise<ExtendedToken> {
    try {
        const url =
            "https://oauth2.googleapis.com/token?" +
            new URLSearchParams({
                client_id: process.env.AUTH_GOOGLE_ID!,
                client_secret: process.env.AUTH_GOOGLE_SECRET!,
                grant_type: "refresh_token",
                refresh_token: token.refreshToken!,
            })

        const response = await fetch(url, {
            headers: {
                "Content-Type": "application/x-www-form-urlencoded",
            },
            method: "POST",
        })

        const refreshedTokens = await response.json()

        if (!response.ok) {
            throw refreshedTokens
        }

        return {
            ...token,
            accessToken: refreshedTokens.access_token,
            expiresAt: Math.floor(Date.now() / 1000 + refreshedTokens.expires_in),
            refreshToken: refreshedTokens.refresh_token ?? token.refreshToken, // Fallback to old refresh token
        }
    } catch (error) {
        console.error("RefreshAccessTokenError", error)
        return {
            ...token,
            error: "RefreshAccessTokenError",
        }
    }
}

export const { handlers, signIn, signOut, auth } = NextAuth({
    providers: [
        Google({
            authorization: {
                params: {
                    scope: "openid email profile https://www.googleapis.com/auth/drive.readonly https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/gmail.send https://www.googleapis.com/auth/gmail.readonly https://www.googleapis.com/auth/spreadsheets",
                    prompt: "consent",
                    access_type: "offline",
                    response_type: "code"
                }
            }
        })
    ],
    callbacks: {
        async signIn({ profile }) {
            // 1. If no domain restriction is set, verify with warning or allow
            if (!process.env.ALLOWED_DOMAIN) {
                console.warn("No ALLOWED_DOMAIN set in environment variables. Allowing all Google logins.");
                return true;
            }

            // 2. Strict Domain Check or Admin Whitelist
            const isAdmin = profile?.email === "thotajonathan.249@gmail.com";
            const isAllowedDomain = profile?.email?.endsWith("@" + process.env.ALLOWED_DOMAIN) ||
                profile?.email?.endsWith(process.env.ALLOWED_DOMAIN);

            return isAdmin || isAllowedDomain || false;
        },
        async jwt({ token, account, user }) {
            // Initial sign in
            if (account && user) {
                return {
                    accessToken: account.access_token,
                    expiresAt: account.expires_at,
                    refreshToken: account.refresh_token,
                    user: {
                        name: user.name,
                        email: user.email,
                        image: user.image,
                    },
                }
            }

            const extendedToken = token as unknown as ExtendedToken;

            // Return previous token if the access token has not expired yet
            // Give a 5-minute buffer (300000ms) to ensure we fetch a new token well before expiry
            if (Date.now() < ((extendedToken.expiresAt as number) * 1000 - 300000)) {
                return token
            }

            // Access token has expired, try to update it
            return await refreshAccessToken(extendedToken) as any;
        },
        async session({ session, token }) {
            const extendedToken = token as unknown as ExtendedToken;
            // Send properties to the client
            const sessionAny = session as unknown as { accessToken?: string; expiresAt?: number; error?: string; user?: any };
            sessionAny.accessToken = extendedToken.accessToken;
            sessionAny.expiresAt = extendedToken.expiresAt;
            sessionAny.error = extendedToken.error;
            if (extendedToken.user) {
                sessionAny.user = extendedToken.user;
            }
            return session;
        }
    },
    pages: {
        signIn: '/login', // Custom login page
    }
})

