import { useState, useEffect } from 'react';

const PROFILE_KEY = 'resume-maker-profile-v1';

export interface UserResume {
    id: 'A' | 'B';
    name: string;
    data: string; // base64
    isPrimary: boolean;
    type: 'docx' | 'pdf' | 'txt';
}

export interface UserProfile {
    firstName: string;
    lastName: string;
    role: string;
    email: string;
    phone: string;
    linkedinURL: string;
    resumes: UserResume[];
}

const DEFAULT_PROFILE: UserProfile = {
    firstName: '',
    lastName: '',
    role: '',
    email: '',
    phone: '',
    linkedinURL: '',
    resumes: []
};

export const useProfile = () => {
    const [profile, setProfile] = useState<UserProfile>(DEFAULT_PROFILE);
    const [isLoaded, setIsLoaded] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem(PROFILE_KEY);
        if (saved) {
            try {
                setProfile(JSON.parse(saved));
            } catch (e) {
                console.error('Failed to parse profile', e);
            }
        }
        setIsLoaded(true);
    }, []);

    const saveProfile = (newProfile: UserProfile) => {
        setProfile(newProfile);
        localStorage.setItem(PROFILE_KEY, JSON.stringify(newProfile));
    };

    const updateProfile = (updates: Partial<UserProfile>) => {
        const newProfile = { ...profile, ...updates };
        saveProfile(newProfile);
    };

    const addResume = (id: 'A' | 'B', name: string, data: string, type: 'docx' | 'pdf' | 'txt') => {
        const otherId = id === 'A' ? 'B' : 'A';
        const existingOther = profile.resumes.find(r => r.id === otherId);

        // If it's the first resume, or the other one isn't primary, make this primary
        const shouldBePrimary = profile.resumes.length === 0 || !existingOther?.isPrimary;

        const newResume: UserResume = {
            id,
            name,
            data,
            type,
            isPrimary: shouldBePrimary
        };

        const newResumes = [
            ...profile.resumes.filter(r => r.id !== id),
            newResume
        ];

        updateProfile({ resumes: newResumes });
    };

    const deleteResume = (id: 'A' | 'B') => {
        const newResumes = profile.resumes.filter(r => r.id !== id);

        // If we deleted the primary resume, make the remaining one primary if it exists
        if (newResumes.length === 1) {
            newResumes[0].isPrimary = true;
        }

        updateProfile({ resumes: newResumes });
    };

    const setPrimaryResume = (id: 'A' | 'B') => {
        const newResumes = profile.resumes.map(r => ({
            ...r,
            isPrimary: r.id === id
        }));
        updateProfile({ resumes: newResumes });
    };

    const getPrimaryResume = () => {
        return profile.resumes.find(r => r.isPrimary);
    };

    return {
        profile,
        updateProfile,
        addResume,
        deleteResume,
        setPrimaryResume,
        getPrimaryResume,
        isLoaded,
        initials: (profile.firstName && profile.lastName) 
            ? `${profile.firstName.charAt(0)}${profile.lastName.charAt(0)}`.toUpperCase() 
            : 'U'
    };
};

/**
 * AI Service - Handles all DeepSeek AI operations
 */

import { getDeepSeekClient } from '@/utils/ai-client';
import { getAnalyzePrompt } from '@/lib/prompts/analyze-prompt';
import { getIntegratePrompt } from '@/lib/prompts/integrate-prompt';
import { AnalysisResult, IntegrationResult } from '@/lib/types/resume.types';
import { AppError } from '@/lib/utils/error-handler';
import { ERROR_MESSAGES } from '@/lib/constants/messages';

export class AIService {
    private get client() {
        return getDeepSeekClient();
    }

    /**
     * Analyze resume against job description
     */
    async analyzeResume(jd: string, resumeText: string): Promise<ReadableStream> {
        const prompt = getAnalyzePrompt(jd, resumeText);
        const encoder = new TextEncoder();

        const stream = new ReadableStream({
            start: async (controller) => {
                try {
                    const completion = await this.client.chat.completions.create({
                        messages: [{ role: 'user', content: prompt }],
                        model: 'deepseek-chat',
                        stream: true,
                        temperature: 0.0,
                        response_format: { type: 'json_object' },
                    });

                    for await (const chunk of completion) {
                        const content = chunk.choices[0]?.delta?.content || '';
                        controller.enqueue(encoder.encode(content));
                    }

                    controller.close();
                } catch (error: any) {
                    console.error("DeepSeek Analyze API Error:", error?.response?.data || error);
                    const errorMsg = error?.response?.data?.error?.message || error?.message || String(error);

                    // Gracefully send error as JSON down the stream instead of killing the TCP connection
                    const errorPayload = JSON.stringify({ error: `AI API Error: ${errorMsg}` });
                    controller.enqueue(encoder.encode(errorPayload));
                    controller.close();
                }
            }
        });

        return stream;
    }

    /**
     * Integrate missing skills into resume
     */
    async integrateSkills(
        resumeText: string,
        missingSkills: string[],
        jd: string
    ): Promise<IntegrationResult> {
        const prompt = getIntegratePrompt(resumeText, missingSkills, jd);

        try {
            const completion = await this.client.chat.completions.create({
                messages: [{ role: 'user', content: prompt }],
                model: 'deepseek-chat',
                temperature: 0.0,
                response_format: { type: 'json_object' },
            });

            const content = completion.choices[0].message.content || '{}';

            // Robust JSON extraction
            let cleanContent = content;
            const jsonMatch = content.match(/\{[\s\S]*\}/);
            if (jsonMatch) {
                cleanContent = jsonMatch[0];
            } else {
                cleanContent = content.replace(/```json\n?|\n?```/g, '').trim();
            }

            try {
                return JSON.parse(cleanContent) as IntegrationResult;
            } catch (parseError) {
                console.error("AI Skill Integration Parse Error. Raw Content:", content);
                throw new AppError('PARSE_ERROR', ERROR_MESSAGES.AI_RESPONSE_INVALID, 500, {
                    rawContent: content,
                    parseError
                });
            }
        } catch (error) {
            if (error instanceof AppError) {
                throw error;
            }
            throw new AppError('AI_ERROR', ERROR_MESSAGES.AI_REQUEST_FAILED, 500, error);
        }
    }

    /**
     * Generate cover letter based on analysis
     */
    async generateCoverLetter(
        candidateName: string,
        jd: string,
        analysisResult: AnalysisResult
    ): Promise<string> {
        const prompt = `
You are a professional cover letter writer.

Candidate: ${candidateName}
Job Description: ${jd}
Match Percentage: ${analysisResult.match_percentage}%

Write a compelling cover letter that:
1. Highlights the candidate's ${analysisResult.match_percentage}% match
2. Addresses the role requirements
3. Is professional and concise (300-400 words)
4. Shows enthusiasm for the position

Return ONLY the cover letter text, no JSON.
`;

        try {
            const completion = await this.client.chat.completions.create({
                messages: [{ role: 'user', content: prompt }],
                model: 'deepseek-chat',
            });

            return completion.choices[0].message.content || '';
        } catch (error) {
            throw new AppError('AI_ERROR', 'Failed to generate cover letter', 500, error);
        }
    }
}

// Export singleton instance
export const aiService = new AIService();

/**
 * Resume Service - Handles resume processing operations
 */

import { auth } from '@/auth';
import { db } from '@/db/drizzle';
import { resumeHistory } from '@/db/schema';
import { eq, desc, and } from 'drizzle-orm';
import { IntegrationResult } from '@/lib/types/resume.types';

export class ResumeService {
    /**
     * Save resume analysis to history
     */
    async saveToHistory(
        candidateName: string,
        jd: string,
        missingSkills: string[],
        integrationResult: IntegrationResult
    ): Promise<void> {
        try {
            const session = await auth();
            const userEmail = session?.user?.email || "local-dev@example.com"; // local dev bypass

            if (!userEmail || !db) {
                console.log('History save skipped: Database not configured');
                return;
            }

            await db.insert(resumeHistory).values({
                userEmail: userEmail,
                candidateName: candidateName,
                jobDescription: jd,
                missingSkills: missingSkills,
                integrationResult: integrationResult,
            });

            console.log('✅ Resume history saved successfully');
        } catch (_error) {
            // Non-fatal: Silently skip history save if DB is down.
            // This prevents "EHOSTUNREACH" errors from spamming production logs.
            console.log('ℹ️ History save skipped (Database unavailable)');
        }
    }

    /**
     * Get user's resume history
     */
    async getHistory(userEmail: string, limit: number = 50) {
        if (!db) {
            return [];
        }

        try {
            const history = await db
                .select()
                .from(resumeHistory)
                .where(eq(resumeHistory.userEmail, userEmail))
                .orderBy(desc(resumeHistory.createdAt))
                .limit(limit);

            return history;
        } catch (error) {
            console.error('Failed to fetch resume history:', error);
            return [];
        }
    }

    /**
     * Delete history entry
     */
    async deleteHistoryEntry(id: string, userEmail: string): Promise<boolean> {
        if (!db) {
            return false;
        }

        try {
            await db
                .delete(resumeHistory)
                .where(
                    and(
                        eq(resumeHistory.id, id),
                        eq(resumeHistory.userEmail, userEmail)
                    )
                );

            return true;
        } catch (error) {
            console.error('Failed to delete history entry:', error);
            return false;
        }
    }
}

